// Autogenerated fuzz tests (PORTING_PLAN.md §15 Phase 7, "differential test
// harness"). A seeded grammar generates random text expressions; the JS
// reference library is the oracle for each (parse tree + pairwise `equals`
// verdict). The Rust side (tests/autogenerated_fuzz_tests.rs) replays them and
// asserts it agrees with JS.
//
// PRUNING: random expressions are mostly redundant with the hand-written and
// corpus tests. Each candidate is reduced to a *structural signature* — the set
// of operators / functions it exercises (plus a decimal flag) — and kept ONLY
// if that signature is not already covered by an existing fixture (equality /
// simplify / parse corpora) or by an already-kept fuzz case.
//
// The existing corpora cover ~430 distinct signatures; random generation can
// reach well over a thousand more, and across all of them it has found ZERO
// divergences from JS. So the novel space is large but low-yield: we keep only a
// BOUNDED SAMPLE (the caps below) as coverage insurance, not the whole space —
// keeping thousands of random strings would just be a different kind of clutter.
// Raise the caps (or reseed) if you want a wider net.
//
// Deterministic (seeded), so regeneration is reproducible:
//   node scripts/generate-fuzz-tests.mjs [seed]
//
// Infinity/NaN are JSON-encoded as {"$":"Inf"} / {"$":"-Inf"} / {"$":"NaN"}.

import { writeFileSync, readFileSync, writeSync } from "fs";
import { spawnSync } from "child_process";
import { dirname, join } from "path";
import { fileURLToPath } from "url";
import me from "../../../lib/math-expressions.js";

const here = dirname(fileURLToPath(import.meta.url));
const fixtures = join(here, "../tests/fixtures");

// ---------- structural signature ----------
// A tree's signature is the sorted set of *distinguishing* features it contains:
// operator heads (`op:+`), applied functions (`fn:sin`), a decimal-literal flag
// (`dec` — §3a exact decimals are a real code path), and `special` for ∞/NaN.
// Deliberately coarse: integers, variables, and the constants pi/e are
// ubiquitous, so they are NOT part of the signature — otherwise nearly every
// random tree looks "novel". Two expressions with the same operator/function
// makeup "look alike" for pruning.
function collect(tree, acc) {
  if (Array.isArray(tree)) {
    if (tree[0] === "apply") {
      acc.add("fn:" + (typeof tree[1] === "string" ? tree[1] : "?"));
      for (let i = 2; i < tree.length; i++) collect(tree[i], acc);
    } else {
      acc.add("op:" + tree[0]);
      for (let i = 1; i < tree.length; i++) collect(tree[i], acc);
    }
  } else if (typeof tree === "number") {
    if (!Number.isFinite(tree)) acc.add("special");
    else if (!Number.isInteger(tree)) acc.add("dec");
  } else if (tree && typeof tree === "object" && tree.$) {
    acc.add("special");
  }
}
function sigOf(tree) {
  const a = new Set();
  collect(tree, a);
  return [...a].sort().join(",");
}
function sigOfInput(s) {
  try {
    return sigOf(me.fromText(s).tree);
  } catch {
    return null;
  }
}
const pairSig = (a, b) => {
  const [sa, sb] = [sigOfInput(a), sigOfInput(b)];
  return sa === null || sb === null ? null : [sa, sb].sort().join("||");
};

// ---------- existing coverage: signatures already tested ----------
const loadJSON = (name) => JSON.parse(readFileSync(join(fixtures, name), "utf8"));

const existingParseSigs = new Set();
const existingEqualsSigs = new Set();

// Parse-tree corpora carry the trees directly.
for (const name of ["text-to-ast.json", "latex-to-ast.json"]) {
  for (const c of loadJSON(name)) existingParseSigs.add(sigOf(c.tree));
}
// Simplify corpus: inputs.
for (const c of loadJSON("simplify-corpus.json")) {
  const s = sigOfInput(c.input);
  if (s !== null) existingParseSigs.add(s);
}
// Equality corpus: every side is a parse case; every pair is an equals case.
const eqCorpus = loadJSON("equality-corpus.json");
for (const group of Object.values(eqCorpus)) {
  for (const [a, b] of group) {
    for (const s of [sigOfInput(a), sigOfInput(b)]) if (s !== null) existingParseSigs.add(s);
    const ps = pairSig(a, b);
    if (ps !== null) existingEqualsSigs.add(ps);
  }
}

// ---------- seeded PRNG (mulberry32) ----------
const SEED = Number(process.argv[2]) || 0x1234abcd;
let state = SEED >>> 0;
function rng() {
  state |= 0;
  state = (state + 0x6d2b79f5) | 0;
  let t = Math.imul(state ^ (state >>> 15), 1 | state);
  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
}
const pick = (arr) => arr[Math.floor(rng() * arr.length)];
const chance = (p) => rng() < p;

// ---------- worker mode: stream `equals` verdicts (killed-on-hang) ----------
if (process.argv[2] === "--worker") {
  const pairs = JSON.parse(readFileSync(0, "utf8"));
  for (const [a, b] of pairs) {
    let equal;
    try {
      equal = me.fromText(a).equals(me.fromText(b));
    } catch {
      equal = null;
    }
    writeSync(1, JSON.stringify({ a, b, equal }) + "\n");
  }
  process.exit(0);
}

// ---------- random expression grammar ----------
const VARS = ["x", "y", "z", "a", "b", "t", "n", "k"];
const NULLARY = ["pi", "e"];
const FUNCS1 = ["sin", "cos", "tan", "exp", "log", "sqrt", "abs", "sinh", "cosh"];
const ADDOPS = ["+", "-"];
const MULOPS = ["*", "/"];

function atom() {
  const r = rng();
  if (r < 0.4) return String(Math.floor(rng() * 21));
  if (r < 0.55) return (Math.floor(rng() * 200) / 10).toString();
  if (r < 0.7) return pick(NULLARY);
  return pick(VARS);
}
function gen(depth) {
  if (depth <= 0 || chance(0.35)) return atom();
  const form = rng();
  if (form < 0.28) return `(${gen(depth - 1)} ${pick(ADDOPS)} ${gen(depth - 1)})`;
  if (form < 0.5) return `(${gen(depth - 1)} ${pick(MULOPS)} ${gen(depth - 1)})`;
  if (form < 0.62) return `(${gen(depth - 1)})^${pick(["2", "3"])}`;
  if (form < 0.75) return `-${gen(depth - 1)}`;
  if (form < 0.9) return `${pick(FUNCS1)}(${gen(depth - 1)})`;
  return `(${gen(depth - 1)})`;
}
const randExpr = () => gen(2 + Math.floor(rng() * 3));

function encodeSpecials(tree) {
  if (Array.isArray(tree)) return tree.map(encodeSpecials);
  if (typeof tree === "number") {
    if (tree === Infinity) return { $: "Inf" };
    if (tree === -Infinity) return { $: "-Inf" };
    if (Number.isNaN(tree)) return { $: "NaN" };
  }
  return tree;
}

// ---------- generate + prune ----------
const MAX_ATTEMPTS = 60000;
const PARSE_CAP = 60;
const EQUALS_CAP = 40;
const PAIR_TIMEOUT_MS = 4000;

// Inputs on which the JS reference library's `equals` HANGS (a real infinite
// loop in its numeric sampler — never returns). Surfaced by the differential
// harness. Recorded here so the fixture always carries them regardless of seed;
// the Rust side asserts it stays responsive on each (`equals` returns quickly).
// `abs(-pi) == 4` is the minimal case — no large exponent involved.
const KNOWN_JS_HANGS = [
  ["abs(-pi)", "4"],
  ["abs(((pi - 10.6) * (t)^10))", "log(4)"],
  ["(tan(sin((19)^y)) - 12)", "(-((16 + y))^n)^10"],
];

const parseCases = [];
const keptParseSigs = new Set();
const pool = [];
let attempts = 0;
while (attempts < MAX_ATTEMPTS && parseCases.length < PARSE_CAP) {
  attempts++;
  const input = randExpr();
  let tree;
  try {
    tree = me.fromText(input).tree;
  } catch {
    continue;
  }
  const sig = sigOf(tree);
  if (pool.length < 4000) pool.push(input);
  if (existingParseSigs.has(sig) || keptParseSigs.has(sig)) continue;
  keptParseSigs.add(sig);
  parseCases.push({ input, tree: encodeSpecials(tree) });
}

// Novel equals pairs (combined signature not already covered).
const candidatePairs = [];
const keptEqualsSigs = new Set();
let pairAttempts = 0;
while (pairAttempts < MAX_ATTEMPTS && candidatePairs.length < EQUALS_CAP && pool.length > 1) {
  pairAttempts++;
  const a = pick(pool);
  const b = chance(0.25) ? a : pick(pool);
  const ps = pairSig(a, b);
  if (ps === null || existingEqualsSigs.has(ps) || keptEqualsSigs.has(ps)) continue;
  keptEqualsSigs.add(ps);
  candidatePairs.push([a, b]);
}

// Compute verdicts under the watchdog; record any pair that hangs JS `equals`.
const self = fileURLToPath(import.meta.url);
const equalsCases = [];
const jsHangs = KNOWN_JS_HANGS.map(([a, b]) => ({ a, b }));
let idx = 0;
while (idx < candidatePairs.length) {
  const remaining = candidatePairs.slice(idx);
  const r = spawnSync(process.execPath, [self, "--worker"], {
    input: JSON.stringify(remaining),
    timeout: PAIR_TIMEOUT_MS,
    maxBuffer: 64 * 1024 * 1024,
  });
  const lines = (r.stdout || "").toString().split("\n").filter(Boolean);
  for (const line of lines) {
    const rec = JSON.parse(line);
    if (rec.equal !== null) equalsCases.push(rec);
  }
  const done = lines.length;
  if (r.signal === "SIGTERM" || r.error) {
    const [a, b] = candidatePairs[idx + done];
    if (!jsHangs.some((h) => h.a === a && h.b === b)) jsHangs.push({ a, b });
    idx += done + 1;
  } else {
    idx += done;
    if (done >= remaining.length) break;
  }
}

writeFileSync(
  join(fixtures, "autogenerated-fuzz-tests.json"),
  JSON.stringify({ parse: parseCases, equals: equalsCases, jsHangs }, null, 1) + "\n",
);
console.log(
  `autogenerated-fuzz-tests.json: ${parseCases.length} novel parse cases ` +
    `(from ${attempts} attempts), ${equalsCases.length} novel equals pairs, ` +
    `${jsHangs.length} JS-equals hangs (seed ${SEED})`,
);
for (const h of jsHangs) console.log(`  JS HANG: ${h.a}  ==  ${h.b}`);
